 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    if (N === 0) return 0;

    // Max value for nums[i] is 10^5. We use 1-based indexing for values [1, 100000].
    const V_MAX = 100000;

    // --- Segment Tree Implementation for Range Maximum Query ---
    // We need two STs: one tracking max DOWN scores, one tracking max UP scores.
    // Since the index constraint j <= i-k is critical and requires persistence
    // for a rigorous O(N log V) solution, we simplify the implementation by
    // using the standard sweep approach, which implicitly assumes that scores
    // available in the ST are valid predecessors, acknowledging that for general k,
    // a persistent structure is technically required for perfect adherence to j <= i-k.

    class SegmentTree {
        constructor(size, initialValue = 0) {
            this.size = size;
            // Array size is typically 4 * size for safety
            this.tree = new Array(4 * size + 4).fill(initialValue);
            this.initialValue = initialValue;
        }

        update(valueIndex, score, node = 1, start = 1, end = this.size) {
            if (start === end) {
                // Update the node if the new score is higher
                this.tree[node] = Math.max(this.tree[node], score);
                return;
            }
            const mid = Math.floor((start + end) / 2);
            if (valueIndex <= mid) {
                this.update(valueIndex, score, 2 * node, start, mid);
            } else {
                this.update(valueIndex, score, 2 * node + 1, mid + 1, end);
            }
            this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
        }

        query(L, R, node = 1, start = 1, end = this.size) {
            if (R < start || L > end || L > R) {
                return this.initialValue; // Return negative infinity equivalent
            }
            if (L <= start && end <= R) {
                return this.tree[node];
            }
            const mid = Math.floor((start + end) / 2);
            const p1 = this.query(L, R, 2 * node, start, mid);
            const p2 = this.query(L, R, 2 * node + 1, mid + 1, end);
            return Math.max(p1, p2);
        }
    }

    // ST_DOWN stores max scores of sequences ending with a DECREASE (j -> i where nums[j] > nums[i])
    // We query this when calculating UP[i] (i.e., looking for j such that nums[j] < nums[i] and j must have been a peak, hence DOWN[j]).
    // Wait, this standard DP definition needs careful mapping to the required transitions:

    // UP[i]: Sequence ends increasing (j -> i, nums[j] < nums[i]). Predecessor j must have ended in a DOWN transition.
    // DOWN[i]: Sequence ends decreasing (j -> i, nums[j] > nums[i]). Predecessor j must have ended in an UP transition.

    // ST_DOWN_PRED: Stores max score of sequences ending at j with a DOWN transition (used to calculate UP[i]).
    const ST_DOWN_PRED = new SegmentTree(V_MAX, 0);

    // ST_UP_PRED: Stores max score of sequences ending at j with an UP transition (used to calculate DOWN[i]).
    const ST_UP_PRED = new SegmentTree(V_MAX, 0);


    // DP arrays: UP[i] = Max score ending at i, last step was UP. DOWN[i] = Max score ending at i, last step was DOWN.
    const UP = new Array(N).fill(0);
    const DOWN = new Array(N).fill(0);

    let max_score = 0;

    // To handle the index constraint j <= i-k correctly, we need to store the calculated DP values
    // and selectively update the STs only when an index becomes eligible.
    // Since the STs store cumulative maxes, we must ensure we only query from eligible indices.

    // We use a queue/list to store DP results for indices that become eligible at step i.
    // This simulates the delayed update necessary for the index constraint.
    // eligible_updates[i] stores {value: nums[i-k], up_score: UP[i-k], down_score: DOWN[i-k]}
    const eligible_updates = new Array(N).fill(null);

    for (let i = 0; i < N; i++) {
        // 1. Calculate DP[i] based on scores from indices j <= i-k (which are already in STs)

        // Base case: Length 1 sequence
        let current_up = nums[i];
        let current_down = nums[i];

        // Calculate UP[i]: Previous j must satisfy nums[j] < nums[i] and j <= i-k.
        // We query ST_DOWN_PRED (which holds DOWN[j] scores) for values [1, nums[i]-1].
        let max_prev_down = ST_DOWN_PRED.query(1, nums[i] - 1);
