                down_score: DOWN[i]
             };
        }
    }

    // --- Re-running the sweep with delayed updates ---
    // The logic above calculated DP[i] assuming all relevant j <= i-k were in the STs.
    // Since we only update STs when i+k is reached, we must perform the DP calculation again
    // or restructure the loop to incorporate the delayed updates properly.

    // Since the initialization of STs to 0 handles the length 1 base case correctly (current_up = nums[i] + 0),
    // we only need to ensure that when we calculate DP[i], the STs reflect all available j <= i-k.

    // Let's restart the structure to ensure updates happen exactly when j = i-k.

    const UP_final = new Array(N).fill(0);
    const DOWN_final = new Array(N).fill(0);

    const ST_DOWN_PRED_final = new SegmentTree(V_MAX, 0);
    const ST_UP_PRED_final = new SegmentTree(V_MAX, 0);
    max_score = 0;

    for (let i = 0; i < N; i++) {

        // 1. Inject scores from j = i-k (if i >= k)
        if (i >= k) {
            const j = i - k;
            const val_j = nums[j];

            // Inject DP[j] into the respective Segment Trees
            // UP[j] becomes available to calculate DOWN[i] (j -> i, decrease)
            ST_UP_PRED_final.update(val_j, UP_final[j]);
            // DOWN[j] becomes available to calculate UP[i] (j -> i, increase)
            ST_DOWN_PRED_final.update(val_j, DOWN_final[j]);
        }

        // 2. Calculate DP[i]

        // Base case: Length 1 sequence
        let current_up = nums[i];
        let current_down = nums[i];

        // Calculate UP[i]: Predecessor j must satisfy nums[j] < nums[i].
        // We query ST_DOWN_PRED_final (which holds DOWN[j]) for values [1, nums[i]-1].
        let max_prev_down = ST_DOWN_PRED_final.query(1, nums[i] - 1);
        current_up = Math.max(current_up, nums[i] + max_prev_down);

        // Calculate DOWN[i]: Predecessor j must satisfy nums[j] > nums[i].
        // We query ST_UP_PRED_final (which holds UP[j]) for values [nums[i]+1, V_MAX].
        let max_prev_up = ST_UP_PRED_final.query(nums[i] + 1, V_MAX);
        current_down = Math.max(current_down, nums[i] + max_prev_up);

        UP_final[i] = current_up;
        DOWN_final[i] = current_down;

        max_score = Math.max(max_score, UP_final[i], DOWN_final[i]);
    }

    return max_score;
}
